SELECT DISTINCT ?city ?cityLabel WHERE {
  ?province wdt:P31/wdt:P279* wd:Q1344695;  # province of Iran
            wdt:P17 wd:Q794;             # in country Iran
            wdt:P36 ?city.               # capital (city)

  SERVICE wikibase:label { 
    bd:serviceParam wikibase:language "en,fa". 
  }
}

SELECT DISTINCT ?city ?cityLabel WHERE {
