SELECT DISTINCT ?river ?riverLabel ?length WHERE {
  ?river wdt:P31 wd:Q4022 ;       
         wdt:P17 wd:Q794 ;       
         wdt:P2043 ?length .     

  FILTER(?length > 100)         

  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],fa,en". }
}

SELECT DISTINCT ?mountain ?mountainLabel ?height WHERE {
