}

SELECT DISTINCT ?writer ?writerLabel ?year WHERE {
  ?writer wdt:P31 wd:Q5 ;
          wdt:P27 wd:Q794 ;
          wdt:P106 wd:Q6625963 ;
          wdt:P569 ?date . # تاریخ تولد

  BIND(YEAR(?date) AS ?year)
  FILTER(?year > 1970)

  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],fa,en". }
}

SELECT DISTINCT ?poet ?poetLabel WHERE {
  ?poet wdt:P31 wd:Q5;       
        wdt:P106 wd:Q49757;  
        wdt:P27 wd:Q794;     
        wdt:P569 ?dob.       
  FILTER(YEAR(?dob) > 1980)  
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],fa". }
}
ORDER BY ?poetLabel

