SELECT DISTINCT ?city ?cityLabel WHERE {
  # provincial capitals in Iran (A_geo)
  ?province wdt:P31/wdt:P279* wd:Q1344695;
            wdt:P17 wd:Q794;
            wdt:P36 ?city.

  ?city wdt:P31/wdt:P279* wd:Q515;
        wdt:P17 wd:Q794.

  # cities with at least one university (B_geo)
  ?univ wdt:P31/wdt:P279* wd:Q3918;
        wdt:P131 ?city.

  SERVICE wikibase:label {
    bd:serviceParam wikibase:language "en,fa".
  }
}

SELECT DISTINCT ?city ?cityLabel WHERE {
  # cities in Iran
  ?city wdt:P31/wdt:P279* wd:Q515;
        wdt:P17 wd:Q794.

  # B_geo: at least one university
  ?univ wdt:P31/wdt:P279* wd:Q3918;
        wdt:P131 ?city.

  # C_geo: at least one museum
  ?museum wdt:P31/wdt:P279* wd:Q33506;
          wdt:P131 ?city.

  SERVICE wikibase:label {
    bd:serviceParam wikibase:language "en,fa".
  }
}

SELECT DISTINCT ?feature ?featureLabel WHERE {
  ?feature wdt:P17 wd:Q794 ;
           wdt:P31 wd:Q4022 ;
           wdt:P2043 ?length .
  FILTER(?length > 100)
  ?feature wdt:P131* wd:Q308864 .
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],fa,en". }
}

SELECT DISTINCT ?feature ?featureLabel WHERE {
  ?feature wdt:P17 wd:Q794 ;
           wdt:P31 wd:Q8502 ;
           wdt:P2044 ?height .
  FILTER(?height > 4000)
  ?feature wdt:P131* wd:Q308864 .
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],fa,en". }
}

SELECT DISTINCT ?feature ?featureLabel WHERE {
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],fa,en". }

  { 
    ?feature wdt:P31 wd:Q4022 ;       
             wdt:P17 wd:Q794 ;       
             wdt:P2043 ?length .
    FILTER(?length > 100)
  }
  UNION
  {
    ?feature wdt:P17 wd:Q794 ; 
             wdt:P31 wd:Q4022 ;
             wdt:P131* wd:Q308864 ;
             wdt:P2043 ?length .
  }
}

SELECT DISTINCT ?feature ?featureLabel WHERE {
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],fa,en". }

  { 
    ?feature wdt:P17 wd:Q794 ; 
             wdt:P31 wd:Q8502 ;
             wdt:P2044 ?height . 
    FILTER(?height > 4000)
  }
  UNION
  { 
    ?feature wdt:P17 wd:Q794 ; 
             wdt:P31 wd:Q8502 ;
             wdt:P131* wd:Q308864 ;
             wdt:P2044 ?height_c .
  }
}

SELECT DISTINCT ?writer ?writerLabel WHERE {
  ?writer wdt:P31 wd:Q5; wdt:P27 wd:Q794 .
  # A: Female Novelist
  ?writer wdt:P106 wd:Q6625963; wdt:P21 wd:Q6581072.
  # B: Born > 1970
  ?writer wdt:P569 ?date. BIND(YEAR(?date) AS ?year) FILTER(?year > 1970)
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],fa,en". }
}

SELECT DISTINCT ?writer ?writerLabel WHERE {
  ?writer wdt:P31 wd:Q5; wdt:P27 wd:Q794 .
  # A: Female Novelist
  ?writer wdt:P106 wd:Q6625963; wdt:P21 wd:Q6581072.
  # C: Poet AND Born > 1980
  ?writer wdt:P106 wd:Q49757 . # Note: This filters writers with two occupations.
  ?writer wdt:P569 ?date. BIND(YEAR(?date) AS ?year) FILTER(?year > 1980)
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],fa,en". }
}

SELECT DISTINCT ?person ?personLabel ?year WHERE {
  ?person wdt:P31 wd:Q5 ;           
          wdt:P27 wd:Q794 ;         
          wdt:P569 ?date .          

  # شغل‌ها
  ?person wdt:P106 wd:Q6625963 .    
  ?person wdt:P106 wd:Q49757 .      

  BIND(YEAR(?date) AS ?year)
  FILTER(?year > 1980)              

  SERVICE wikibase:label { 
    bd:serviceParam wikibase:language "[AUTO_LANGUAGE],fa,en". 
  }
}

SELECT DISTINCT ?writer ?writerLabel ?year WHERE {

  {
    ?writer wdt:P31 wd:Q5 ;
            wdt:P27 wd:Q794 ; 
            wdt:P106 wd:Q6625963 ;  
            wdt:P21 wd:Q6581072 ;    
            wdt:P569 ?date .         
  }
  UNION
  {
    ?writer wdt:P31 wd:Q5 ;
            wdt:P27 wd:Q794 ;
            wdt:P106 wd:Q6625963 ;
            wdt:P569 ?date .
    FILTER(YEAR(?date) > 1970)
  }

  BIND(YEAR(?date) AS ?year)

  SERVICE wikibase:label {
    bd:serviceParam wikibase:language "[AUTO_LANGUAGE],fa,en".
  }
}

SELECT DISTINCT ?person ?personLabel WHERE {

  {
    # Writers born after 1970
    ?person wdt:P31 wd:Q5 ;             # human
            wdt:P27 wd:Q794 ;           # Iranian
            wdt:P106 wd:Q6625963 ;      # writer/novelist
            wdt:P569 ?date1 .
    BIND(YEAR(?date1) AS ?year)
    FILTER(?year > 1970)
  }

  UNION

  {
    # Poets born after 1980
    ?person wdt:P31 wd:Q5 ;             # human
            wdt:P27 wd:Q794 ;           # Iranian
            wdt:P106 wd:Q49757 ;        # poet
            wdt:P569 ?date2 .
    BIND(YEAR(?date2) AS ?year)
    FILTER(?year > 1980)
  }

  SERVICE wikibase:label { 
    bd:serviceParam wikibase:language "[AUTO_LANGUAGE],fa,en".
  }
}

