SELECT DISTINCT ?city ?cityLabel WHERE {
  # A_geo: provincial capitals in Iran
  ?province wdt:P31/wdt:P279* wd:Q1344695;   # Iranian province
            wdt:P17 wd:Q794;              # in Iran
            wdt:P36 ?city.               # capital (city)

  ?city wdt:P31/wdt:P279* wd:Q515;
        wdt:P17 wd:Q794.

  # B_geo: cities with at least one university
  ?univ wdt:P31/wdt:P279* wd:Q3918;
        wdt:P131 ?city.

  # ¬C_geo: city does NOT have a museum
  FILTER NOT EXISTS {
    ?museum wdt:P31/wdt:P279* wd:Q33506;
            wdt:P131 ?city.
  }

  SERVICE wikibase:label {
    bd:serviceParam wikibase:language "en,fa".
  }
}

SELECT DISTINCT ?city ?cityLabel WHERE {
  # A_geo: provincial capitals in Iran
  ?province wdt:P31/wdt:P279* wd:Q1344695;   # Iranian province
            wdt:P17 wd:Q794;              # in Iran
            wdt:P36 ?city.               # capital (city)

  ?city wdt:P31/wdt:P279* wd:Q515;        # city
        wdt:P17 wd:Q794.                 # in Iran

  # ¬C_geo: city does NOT have a museum
  FILTER NOT EXISTS {
    ?museum wdt:P31/wdt:P279* wd:Q33506;  # museum
            wdt:P131 ?city.              # located in city
  }

  SERVICE wikibase:label {
    bd:serviceParam wikibase:language "en,fa".
  }
}

SELECT DISTINCT ?city ?cityLabel WHERE {
  # A_geo: provincial capitals in Iran
  ?province wdt:P31/wdt:P279* wd:Q1344695;   # Iranian province
            wdt:P17 wd:Q794;              # in Iran
            wdt:P36 ?city.               # capital

  ?city wdt:P31/wdt:P279* wd:Q515;
        wdt:P17 wd:Q794.

  {
    # B_geo: cities with at least one university
    ?univ wdt:P31/wdt:P279* wd:Q3918;
          wdt:P131 ?city.
  }
  UNION
  {
    # C_geo: cities with at least one museum
    ?museum wdt:P31/wdt:P279* wd:Q33506;
            wdt:P131 ?city.
  }

  SERVICE wikibase:label {
    bd:serviceParam wikibase:language "en,fa".
  }
}

